{
  "query": "mutation CreateAcademicYear($input: CreateAcademicYearInput!) { createAcademicYear(input: $input) { id name startDate endDate isActive } }",
  "variables": {
    "input": {
      "name": "2025-26",
      "startDate": "2025-06-01",
      "endDate": "2026-05-31"
    }
  }
}

{
  "query": "query { listAcademicYears { id name startDate endDate isActive } }"
}

{
  "query": "mutation CreateCampus($input: CreateCampusInput!) { createCampus(input: $input) { id name code type isActive } }",
  "variables": {
    "input": {
      "name": "Main Campus",
      "code": "MAIN",
      "type": "SCHOOL",
      "address": "Bengaluru, Karnataka"
    }
  }
}

{
  "query": "query { listCampuses { id name code type isActive } }"
}

{
  "query": "query DashboardOverview($input: DashboardOverviewInput!) { dashboardOverview(input: $input) { totals { activeStudents staff admissionsToday } campusName generatedAt } }",
  "variables": {
    "input": {
      "campusId": "{{campus_id}}",
      "range": {
        "preset": "LAST_30_DAYS"
      }
    }
  }
}

{
  "query": "query { me { id email fullName firstName lastName permissions roles tenantId } }"
}

{
  "query": "query { listUsers { edges { cursor node { id email fullName status } } pageInfo { hasNextPage } } }"
}

{
  "query": "mutation InviteStaff($input: InviteStaffInput!) { inviteStaff(input: $input) { success membershipId } }",
  "variables": {
    "input": {
      "email": "{{staff_email}}",
      "fullName": "Test Teacher",
      "roleIds": [],
      "campusIds": [
        "{{campus_id}}"
      ],
      "allCampuses": false
    }
  }
}

{
  "query": "mutation UpdateEnquiry($id: ID!, $input: AWSJSON!) { updateEnquiry(id: $id, input: $input) }",
  "variables": {
    "id": "{{enquiry_id}}",
    "input": "{\"status\":\"CONTACTED\",\"notes\":\"Called and confirmed interest\"}"
  }
}

{
  "query": "mutation ReviewApplication($id: ID!, $input: AWSJSON!) { reviewApplication(id: $id, input: $input) }",
  "variables": {
    "id": "{{application_id}}",
    "input": "{\"decision\":\"UNDER_REVIEW\",\"remarks\":\"Documents verified, proceeding to review\"}"
  }
}

{
  "query": "mutation RejectApplication($id: ID!, $reason: String) { rejectApplication(id: $id, reason: $reason) }",
  "variables": {
    "id": "{{application_id}}",
    "reason": "Documents incomplete"
  }
}

{
  "query": "mutation VerifyDocument($applicationId: ID!, $documentId: ID!, $input: AWSJSON!) { verifyDocument(applicationId: $applicationId, documentId: $documentId, input: $input) }",
  "variables": {
    "applicationId": "{{application_id}}",
    "documentId": "birth_certificate",
    "input": "{\"verified\":true,\"remarks\":\"Document looks valid\"}"
  }
}

{
  "query": "mutation UpdateFeeStructure($id: ID!, $input: AWSJSON!) { updateFeeStructure(id: $id, input: $input) }",
  "variables": {
    "id": "{{fee_structure_id}}",
    "input": "{\"name\":\"Grade 10 Annual Fee 2025-26\"}"
  }
}

{
  "query": "mutation ReviseInvoice($id: ID!, $input: AWSJSON!) { reviseInvoice(id: $id, input: $input) }",
  "variables": {
    "id": "{{invoice_id}}",
    "input": "{\"newAmount\":48000,\"reason\":\"Scholarship discount applied\"}"
  }
}

{
  "query": "mutation CancelInvoice($id: ID!, $reason: String) { cancelInvoice(id: $id, reason: $reason) }",
  "variables": {
    "id": "{{invoice_id}}",
    "reason": "Cancelled for testing"
  }
}

{
  "query": "mutation RecordPayment($input: AWSJSON!) { recordPayment(input: $input) }",
  "variables": {
    "input": "{\"invoiceId\":\"{{invoice_id}}\",\"studentId\":\"{{student_id}}\",\"campusId\":\"{{campus_id}}\",\"amount\":5000,\"method\":\"UPI\",\"referenceNumber\":\"UPI123456\",\"allocationMode\":\"MANUAL\",\"remarks\":\"UPI payment — manual allocation\"}"
  }
}

{
  "query": "mutation CollectPaymentByStudent($studentId: ID!, $input: AWSJSON!) { collectPaymentByStudent(studentId: $studentId, input: $input) }",
  "variables": {
    "studentId": "{{student_id}}",
    "input": "{\"amount\":5000,\"method\":\"CASH\",\"remarks\":\"Bulk collect across all outstanding invoices\"}"
  }
}

{
  "query": "mutation CreatePaymentOrder($invoiceId: ID!, $amount: Float) { createPaymentOrder(invoiceId: $invoiceId, amount: $amount) }",
  "variables": {
    "invoiceId": "{{invoice_id}}",
    "amount": null
  }
}

{
  "query": "mutation ReplaceSectionTimetable($sectionId: ID!, $slots: [TimetableSlotInput!]!) { replaceSectionTimetable(sectionId: $sectionId, slots: $slots) { sectionId slots { id sectionId dayOfWeek periodNumber startTime endTime label isBreak } } }",
  "variables": {
    "sectionId": "{{section_id}}",
    "slots": [
      {
        "dayOfWeek": "MON",
        "periodNumber": 1,
        "startTime": "09:00",
        "endTime": "09:45",
        "subjectId": "{{subject_id}}",
        "teacherProfileId": "{{staff_profile_id}}",
        "room": "101",
        "label": "Mathematics",
        "isBreak": false
      },
      {
        "dayOfWeek": "MON",
        "periodNumber": 2,
        "startTime": "09:45",
        "endTime": "10:00",
        "label": "Break",
        "isBreak": true
      }
    ]
  }
}

{
  "query": "query GetSectionTimetable($sectionId: ID!) { getSectionTimetable(sectionId: $sectionId) { sectionId slots { id dayOfWeek periodNumber startTime endTime label isBreak } } }",
  "variables": {
    "sectionId": "{{section_id}}"
  }
}

{
  "query": "query GetTeacherTimetable($profileId: ID!) { getTeacherTimetable(profileId: $profileId) { slots { id sectionId dayOfWeek periodNumber startTime endTime label isBreak } incharges { id role } } }",
  "variables": {
    "profileId": "{{staff_profile_id}}"
  }
}

{
  "query": "query { listStudents { items { id firstName lastName fullName status admissionNo } nextToken } }"
}

{
  "query": "mutation MarkSectionAttendance($input: BulkAttendanceInput!) { markSectionAttendance(input: $input) { id studentId status date } }",
  "variables": {
    "input": {
      "sectionId": "{{section_id}}",
      "campusId": "{{campus_id}}",
      "date": "2026-05-08",
      "records": [
        {
          "studentId": "{{student_id}}",
          "status": "PRESENT"
        }
      ]
    }
  }
}

{
  "query": "query GetSectionAttendance($sectionId: ID!, $date: AWSDate!) { getSectionAttendance(sectionId: $sectionId, date: $date) { id studentId status date } }",
  "variables": {
    "sectionId": "{{section_id}}",
    "date": "2026-05-08"
  }
}

{
  "query": "query GetAttendanceSummary($sectionId: ID!, $from: AWSDate!, $to: AWSDate!) { getSectionAttendanceSummary(sectionId: $sectionId, from: $from, to: $to) { sectionId from to totalDays } }",
  "variables": {
    "sectionId": "{{section_id}}",
    "from": "2025-06-01",
    "to": "2025-12-31"
  }
}

{
  "query": "query GetStudentAttendance($studentId: ID!, $from: AWSDate!, $to: AWSDate!) { getStudentAttendance(studentId: $studentId, from: $from, to: $to) { id studentId status date } }",
  "variables": {
    "studentId": "{{student_id}}",
    "from": "2025-06-01",
    "to": "2025-12-31"
  }
}

{
  "query": "mutation EnterMarks($examId: ID!, $input: AWSJSON!) { enterMarks(examId: $examId, input: $input) }",
  "variables": {
    "examId": "{{exam_id}}",
    "input": "{\"studentId\":\"{{student_id}}\",\"marksObtained\":78,\"maxMarks\":100,\"grade\":\"A\",\"remarks\":\"Good performance\"}"
  }
}

{
  "query": "mutation UpdateExam($id: ID!, $input: AWSJSON!) { updateExam(id: $id, input: $input) }",
  "variables": {
    "id": "{{exam_id}}",
    "input": "{\"name\":\"Term 1 Exam 2025 (Updated)\"}"
  }
}

{
  "query": "mutation CreateAnnouncement($input: AWSJSON!) { createAnnouncement(input: $input) }",
  "variables": {
    "input": "{\"title\":\"School Notice — Test\",\"content\":\"This is a test announcement.\",\"campusId\":\"{{campus_id}}\",\"targetAudience\":\"ALL\"}"
  }
}

{
  "query": "mutation GenerateUploadUrl($contentType: String!, $filename: String!) { generateUploadUrl(contentType: $contentType, filename: $filename) { uploadUrl key } }",
  "variables": {
    "contentType": "application/pdf",
    "filename": "test-document.pdf"
  }
}
